}

export interface Zone {
  id: string;
  name: string;
  description?: string;
  center: Coordinates;
  radius: number; // in meters
  entryMusic?: MusicTrack;
  exitMusic?: MusicTrack;
}

export enum AppState {
  MAP_VIEW,
  ADDING_ZONE,
}

export interface GeminiResponse {
  suggestedName: string;
  description: string;
}

import { Coordinates } from "./types";

export const DEFAULT_CENTER: Coordinates = { lat: 19.4326, lng: -99.1332 }; // Mexico City as default
export const DEFAULT_ZOOM = 15;
export const DEFAULT_RADIUS = 50; // meters

// Haversine formula to calculate distance between two points in meters
export const calculateDistance = (coord1: Coordinates, coord2: Coordinates): number => {
  const R = 6371e3; // Earth radius in meters
  const φ1 = (coord1.lat * Math.PI) / 180;
  const φ2 = (coord2.lat * Math.PI) / 180;
  const Δφ = ((coord2.lat - coord1.lat) * Math.PI) / 180;
  const Δλ = ((coord2.lng - coord1.lng) * Math.PI) / 180;

  const a =
    Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +
    Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) * Math.sin(Δλ / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

  return R * c;
};

import { GoogleGenAI, Type } from "@google/genai";
import { GeminiResponse } from "../types";

export const generateZoneDetails = async (
  lat: number,
  lng: number
): Promise<GeminiResponse> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key not found");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Suggest a creative, short name and a 1-sentence vibe description for a location music zone at coordinates: ${lat}, ${lng}. Assume it's a generic urban area if specific data is missing.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestedName: {
              type: Type.STRING,
              description: "A short, catchy name for the location",
            },
            description: {
              type: Type.STRING,
              description: "A very short description of the vibe",
            },
          },
          required: ["suggestedName", "description"],
        },
      },
    });

    if (response.text) {
      return JSON.parse(response.text) as GeminiResponse;
    }

    return {
      suggestedName: "New Zone",
      description: "A custom music zone",
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      suggestedName: "My Location",
      description: "Manually added location",
    };
  }
};

import React, { useEffect, useRef, useState } from 'react';
import { Zone, Coordinates } from '../types';
import { calculateDistance } from '../constants';

interface AudioEngineProps {
  userLocation: Coordinates | null;
  zones: Zone[];
  isTracking: boolean;
}

const AudioEngine: React.FC<AudioEngineProps> = ({ userLocation, zones, isTracking }) => {
  const [activeZoneId, setActiveZoneId] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Initialize audio element
  useEffect(() => {
    audioRef.current = new Audio();
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.src = "";
      }
    };
  }, []);

  useEffect(() => {
    if (!userLocation || !isTracking || zones.length === 0 || !audioRef.current) return;

    // Find if we are inside any zone
    const currentZone = zones.find(zone => {
      const distance = calculateDistance(userLocation, zone.center);
      return distance <= zone.radius;
    });

    if (currentZone) {
      // WE ARE INSIDE A ZONE
      if (activeZoneId !== currentZone.id) {
        // We just entered a new zone
        console.log(`Entering zone: ${currentZone.name}`);

        if (currentZone.entryMusic) {
          audioRef.current.src = currentZone.entryMusic.url;
          audioRef.current.play().catch(e => console.log("Autoplay prevented:", e));
        } else {
          audioRef.current.pause();
        }

        setActiveZoneId(currentZone.id);
      }
    } else {
      // WE ARE OUTSIDE ALL ZONES
      if (activeZoneId !== null) {
        // We just left a zone
        const previousZone = zones.find(z => z.id === activeZoneId);
        console.log(`Leaving zone: ${previousZone?.name}`);

        if (previousZone && previousZone.exitMusic) {
            audioRef.current.src = previousZone.exitMusic.url;
            audioRef.current.play().catch(e => console.log("Autoplay prevented:", e));
        } else {
            // If no exit music defined, maybe just stop the entry music?
            // For this app, let's stop.
            audioRef.current.pause();
        }

        setActiveZoneId(null);
      }
    }
  }, [userLocation, zones, isTracking, activeZoneId]);

  return (
    <div className="hidden">
      {/* Audio logic is headless */}
    </div>
  );
};

export default AudioEngine;

import React, { useState } from 'react';
import { Coordinates, Zone, MusicTrack } from '../types';
import { X, Music, Upload, Loader2, Sparkles } from 'lucide-react';
import { generateZoneDetails } from '../services/geminiService';

interface ZoneModalProps {
  location: Coordinates;
  onSave: (zone: Zone) => void;
  onCancel: () => void;
}

const ZoneModal: React.FC<ZoneModalProps> = ({ location, onSave, onCancel }) => {
  const [name, setName] = useState('');
  const [radius, setRadius] = useState(50);
  const [entryFile, setEntryFile] = useState<File | null>(null);
  const [exitFile, setExitFile] = useState<File | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'entry' | 'exit') => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (type === 'entry') setEntryFile(file);
      else setExitFile(file);
    }
  };

  const handleGeminiSuggestion = async () => {
    setIsGenerating(true);
    try {
      const details = await generateZoneDetails(location.lat, location.lng);
      setName(details.suggestedName);
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = () => {
    if (!name) return;

    const newZone: Zone = {
      id: Date.now().toString(),
      name,
      center: location,
      radius,
      entryMusic: entryFile ? {
        file: entryFile,
        url: URL.createObjectURL(entryFile),
        name: entryFile.name
      } : undefined,
      exitMusic: exitFile ? {
        file: exitFile,
        url: URL.createObjectURL(exitFile),
        name: exitFile.name
      } : undefined,
    };

    onSave(newZone);
  };

  return (
    <div className="fixed inset-0 z-[1000] flex items-end sm:items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="bg-gray-800 border border-gray-700 w-full max-w-md rounded-2xl p-6 shadow-2xl flex flex-col gap-4 animate-in slide-in-from-bottom-10 fade-in duration-300">

        <div className="flex justify-between items-center">
          <h2 className="text-xl font-bold text-white flex items-center gap-2">
            <Music className="w-5 h-5 text-indigo-400" />
            Configurar Zona
          </h2>
          <button onClick={onCancel} className="p-2 hover:bg-gray-700 rounded-full text-gray-400">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="space-y-4">

          {/* Name Input with AI Gen */}
          <div className="flex gap-2 items-end">
            <div className="flex-1">
              <label className="text-xs text-gray-400 font-semibold uppercase">Nombre del Lugar</label>
              <input 
                type="text" 
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Ej. Gimnasio, Casa, Trabajo"
                className="w-full bg-gray-900 border border-gray-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-indigo-500 outline-none mt-1"
              />
            </div>
            <button 
              onClick={handleGeminiSuggestion}
