import React, { useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup, Circle, useMap, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import { Coordinates, Zone } from '../types';
import { MapPin, Navigation } from 'lucide-react';

// Fix Leaflet Default Icon
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';

let DefaultIcon = L.icon({
    iconUrl: icon,
    shadowUrl: iconShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41]
});
L.Marker.prototype.options.icon = DefaultIcon;

// Sub-component to handle map clicks
const MapClickEvent = ({ onClick }: { onClick: (coords: Coordinates) => void }) => {
  useMapEvents({
    click(e) {
      onClick({ lat: e.latlng.lat, lng: e.latlng.lng });
    },
  });
  return null;
};

// Sub-component to center map
const MapRecenter = ({ center }: { center: Coordinates }) => {
  const map = useMap();
  useEffect(() => {
    map.setView([center.lat, center.lng]);
  }, [center, map]);
  return null;
};

interface MapWrapperProps {
  userLocation: Coordinates;
  zones: Zone[];
  onMapClick: (coords: Coordinates) => void;
  activeZoneId?: string;
}

const MapWrapper: React.FC<MapWrapperProps> = ({ userLocation, zones, onMapClick }) => {

  // Custom user icon
  const userIcon = new L.DivIcon({
    className: 'bg-transparent',
    html: `<div class="w-6 h-6 bg-blue-500 rounded-full border-2 border-white shadow-lg animate-pulse ring-4 ring-blue-500/30"></div>`,
    iconSize: [24, 24],
    iconAnchor: [12, 12]
  });

  return (
    <div className="w-full h-full relative z-0">
      <MapContainer 
        center={[userLocation.lat, userLocation.lng]} 
        zoom={16} 
        style={{ height: '100%', width: '100%' }}
        zoomControl={false}
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />

        <MapClickEvent onClick={onMapClick} />
        <MapRecenter center={userLocation} />

        {/* User Location Marker */}
        <Marker position={[userLocation.lat, userLocation.lng]} icon={userIcon}>
          <Popup>Estás aquí</Popup>
        </Marker>

        {/* Zones */}
        {zones.map((zone) => (
          <React.Fragment key={zone.id}>
             {/* The visual circle on map */}
            <Circle 
              center={[zone.center.lat, zone.center.lng]}
              radius={zone.radius}
              pathOptions={{ 
                color: '#6366f1', 
                fillColor: '#818cf8', 
                fillOpacity: 0.2,
                weight: 2
              }}
            />
            {/* The Clickable marker for the zone */}
            <Marker position={[zone.center.lat, zone.center.lng]}>
              <Popup>
                <div className="text-center">
                    <strong className="block text-lg">{zone.name}</strong>
                    <div className="text-xs text-gray-500 mt-1">
                        {zone.entryMusic ? '✅ Entrada configurada' : '❌ Sin entrada'} <br/>
                        {zone.exitMusic ? '✅ Salida configurada' : '❌ Sin salida'}
                    </div>
                </div>
              </Popup>
            </Marker>
          </React.Fragment>
        ))}

      </MapContainer>

      {/* Decorative overlay for "No Internet" hint */}
      <div className="absolute bottom-6 left-6 z-[400] bg-white/90 backdrop-blur text-black text-[10px] px-2 py-1 rounded shadow pointer-events-none opacity-60">
        Map tiles require internet. Logic works offline.
      </div>
    </div>
  );
};

export default MapWrapper;

import React, { useState, useEffect, useCallback } from 'react';
import { Coordinates, Zone, AppState } from './types';
import { DEFAULT_CENTER } from './constants';
import MapWrapper from './components/MapWrapper';
import ZoneModal from './components/ZoneModal';
import AudioEngine from './components/AudioEngine';
import { MapPin, Plus, Music2, Navigation, AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [userLocation, setUserLocation] = useState<Coordinates>(DEFAULT_CENTER);
  const [zones, setZones] = useState<Zone[]>([]);
  const [appState, setAppState] = useState<AppState>(AppState.MAP_VIEW);
  const [pendingZoneCoords, setPendingZoneCoords] = useState<Coordinates | null>(null);
  const [isTracking, setIsTracking] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [permissionStatus, setPermissionStatus] = useState<PermissionState | null>(null);

  // --- Geolocation Logic ---
  const startTracking = useCallback(() => {
    if (!navigator.geolocation) {
      setError("Geolocation is not supported by your browser");
      return;
    }

    setIsTracking(true);
    const watchId = navigator.geolocation.watchPosition(
      (position) => {
        setUserLocation({
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        });
        setError(null);
      },
      (err) => {
        console.error(err);
        setError("Necesitamos acceso a tu ubicación para funcionar.");
        setIsTracking(false);
      },
      {
        enableHighAccuracy: true,
        timeout: 5000,
        maximumAge: 0,
      }
    );

    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  useEffect(() => {
    // Initial start
    const stopTracking = startTracking();
    return () => { 
        if(stopTracking) stopTracking(); 
    };
  }, [startTracking]);

  // --- Handlers ---

  const handleMapClick = (coords: Coordinates) => {
    setPendingZoneCoords(coords);
    setAppState(AppState.ADDING_ZONE);
  };

  const handleSaveZone = (newZone: Zone) => {
    setZones((prev) => [...prev, newZone]);
    setAppState(AppState.MAP_VIEW);
    setPendingZoneCoords(null);
  };

  const handleCancelZone = () => {
    setAppState(AppState.MAP_VIEW);
    setPendingZoneCoords(null);
  };

  return (
    <div className="h-screen w-screen flex flex-col bg-gray-900 text-white relative overflow-hidden">

      {/* Header */}
      <header className="absolute top-0 left-0 right-0 z-[500] p-4 pointer-events-none">
        <div className="flex justify-between items-start">
            <div className="bg-gray-900/80 backdrop-blur-md p-3 rounded-2xl shadow-lg border border-gray-700 pointer-events-auto">
                <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-400 flex items-center gap-2">
                    <Music2 className="text-indigo-400" /> GeoGroove
                </h1>
                <p className="text-xs text-gray-400 mt-1">
                    {zones.length} zonas activas • {isTracking ? <span className="text-green-400">Rastreando GPS</span> : <span className="text-red-400">GPS Pausado</span>}
                </p>
            </div>
        </div>
      </header>

      {/* Map Area */}
      <div className="flex-1 relative">
        <MapWrapper 
          userLocation={userLocation} 
          zones={zones} 
          onMapClick={handleMapClick}
        />
      </div>

      {/* Bottom Controls / Info */}
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-[500] w-full max-w-sm px-4 pointer-events-none">
         {error && (
             <div className="bg-red-500/90 text-white p-3 rounded-lg mb-4 text-sm flex items-center gap-2 shadow-lg backdrop-blur pointer-events-auto">
                 <AlertTriangle size={18} /> {error}
             </div>
         )}

         <div className="bg-gray-900/90 backdrop-blur-lg border border-gray-700 p-4 rounded-2xl shadow-2xl pointer-events-auto">
            <p className="text-sm text-center text-gray-300 mb-3">
                Toca el mapa para agregar música a un lugar.
            </p>
            <div className="flex gap-2">
                <button 
                    onClick={() => {
                        // Force recenter manually
                        const current = userLocation;
                        setUserLocation({...current}); 
                    }}
                    className="flex-1 bg-gray-700 hover:bg-gray-600 text-white py-2 rounded-lg text-sm font-medium transition-colors flex items-center justify-center gap-2"
                >
                    <Navigation size={16} /> Recentrar
                </button>
            </div>
         </div>
      </div>

      {/* Modals */}
      {appState === AppState.ADDING_ZONE && pendingZoneCoords && (
        <ZoneModal 
          location={pendingZoneCoords} 
          onSave={handleSaveZone} 
          onCancel={handleCancelZone} 
        />
      )}

      {/* Logic Components */}
      <AudioEngine 
        userLocation={userLocation}
        zones={zones}
        isTracking={isTracking}
      />

    </div>
  );
};

export default App;

