                      {isTestMode ? (
                        <span className="text-xs font-bold text-yellow-400 bg-yellow-400/10 px-2 py-0.5 rounded border border-yellow-400/20">MODO PRUEBA</span>
                      ) : (
                        isTracking ? <span className="text-xs text-green-400">● GPS Activo</span> : <span className="text-xs text-red-400">● GPS Inactivo</span>
