import React, { useEffect, useRef, useState } from 'react';
import { Zone, Coordinates, PlayerState } from '../types';
import { calculateDistance } from '../constants';

interface AudioEngineProps {
  userLocation: Coordinates | null;
  zones: Zone[];
  isTracking: boolean;
  onStateChange: (state: PlayerState) => void;
  isPaused: boolean;
  onResetPause: () => void;
}

const AudioEngine: React.FC<AudioEngineProps> = ({ 
  userLocation, 
  zones, 
  isTracking, 
  onStateChange,
  isPaused,
  onResetPause
}) => {
  const [activeZoneId, setActiveZoneId] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Keep track of current metadata to restore state when unpausing
  const currentMeta = useRef<{
    trackName?: string;
    zoneName?: string;
    type?: 'entry' | 'exit';
  }>({});

  // Initialize audio element
  useEffect(() => {
    audioRef.current = new Audio();
    // Logic for when non-looping audio ends (exit music)
    audioRef.current.onended = () => {
       if (!audioRef.current?.loop) {
          onStateChange({ isPlaying: false });
       }
    };
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.src = "";
      }
    };
  }, [onStateChange]);

  // Handle Play/Pause toggle
  useEffect(() => {
    if (!audioRef.current) return;

    if (isPaused) {
      if (!audioRef.current.paused) {
        audioRef.current.pause();
        onStateChange({ 
            isPlaying: false,
            ...currentMeta.current 
        });
      }
    } else {
      // If unpaused and we have a valid source that isn't finished (or is looping)
      if (audioRef.current.src && (audioRef.current.loop || !audioRef.current.ended)) {
         audioRef.current.play().catch(e => console.log("Resume failed", e));
         onStateChange({ 
            isPlaying: true,
            ...currentMeta.current
         });
      }
    }
  }, [isPaused, onStateChange]);

  useEffect(() => {
    if (!userLocation || !isTracking || !audioRef.current) return;

    if (zones.length === 0) return;

    // Find if we are inside any zone
    const currentZone = zones.find(zone => {
      const distance = calculateDistance(userLocation, zone.center);
      return distance <= zone.radius;
    });

    if (currentZone) {
      // WE ARE INSIDE A ZONE
      if (activeZoneId !== currentZone.id) {
        // Entering new zone
        console.log(`Entering zone: ${currentZone.name}`);

        // Reset manual pause for new location
        onResetPause();

        if (currentZone.entryMusic) {
          audioRef.current.src = currentZone.entryMusic.url;
          audioRef.current.loop = true; // LOOP ENABLED FOR ENTRY

          currentMeta.current = {
             trackName: currentZone.entryMusic.name,
             zoneName: currentZone.name,
             type: 'entry'
          };

          audioRef.current.play().catch(e => console.log("Autoplay prevented:", e));

          onStateChange({
            isPlaying: true,
            ...currentMeta.current
          });
        } else {
          audioRef.current.pause();
          onStateChange({ isPlaying: false });
        }

        setActiveZoneId(currentZone.id);
      }
    } else {
      // WE ARE OUTSIDE ALL ZONES
      if (activeZoneId !== null) {
        // Leaving zone
        const previousZone = zones.find(z => z.id === activeZoneId);
        console.log(`Leaving zone: ${previousZone?.name}`);

        // Reset manual pause for exit event
        onResetPause();

        if (previousZone && previousZone.exitMusic) {
            audioRef.current.src = previousZone.exitMusic.url;
            audioRef.current.loop = false; // NO LOOP FOR EXIT

            currentMeta.current = {
                trackName: previousZone.exitMusic.name,
                zoneName: previousZone.name + " (Saliendo)",
                type: 'exit'
            };

            audioRef.current.play().catch(e => console.log("Autoplay prevented:", e));

            onStateChange({
                isPlaying: true,
                ...currentMeta.current
            });
        } else {
            // No exit music, just stop
            audioRef.current.pause();
            audioRef.current.src = "";
            onStateChange({ isPlaying: false });
        }

        setActiveZoneId(null);
      }
    }
  }, [userLocation, zones, isTracking, activeZoneId, onStateChange, onResetPause]);

  return (
    <div className="hidden">
      {/* Audio logic is headless */}
    </div>
  );
};

export default AudioEngine;

import React, { useState, useEffect, useCallback } from 'react';
import { Coordinates, Zone, AppState, PlayerState } from './types';
import { DEFAULT_CENTER } from './constants';
import MapWrapper from './components/MapWrapper';
import ZoneModal from './components/ZoneModal';
import AudioEngine from './components/AudioEngine';
import MusicPlayer from './components/MusicPlayer';
import { MapPin, Plus, Music2, Navigation, AlertTriangle, FlaskConical, Move } from 'lucide-react';

const App: React.FC = () => {
  const [userLocation, setUserLocation] = useState<Coordinates>(DEFAULT_CENTER);
  const [zones, setZones] = useState<Zone[]>([]);
  const [appState, setAppState] = useState<AppState>(AppState.MAP_VIEW);
  const [pendingZoneCoords, setPendingZoneCoords] = useState<Coordinates | null>(null);

  // States for tracking and modes
  const [isTracking, setIsTracking] = useState(false);
  const [isTestMode, setIsTestMode] = useState(false);
  const [isAutoCenterEnabled, setIsAutoCenterEnabled] = useState(true);

  const [error, setError] = useState<string | null>(null);

  // Player State
  const [playerState, setPlayerState] = useState<PlayerState>({ isPlaying: false });
  const [isManualPaused, setIsManualPaused] = useState(false);

  // --- Geolocation Logic ---
  useEffect(() => {
    let watchId: number | null = null;

    if (isTestMode) {
        setIsTracking(false);
    } else {
        if (!navigator.geolocation) {
          setError("Geolocation is not supported by your browser");
          return;
        }

        setIsTracking(true);
        watchId = navigator.geolocation.watchPosition(
          (position) => {
            setUserLocation({
              lat: position.coords.latitude,
              lng: position.coords.longitude,
            });
            setError(null);
          },
          (err) => {
            console.error(err);
            setError("Necesitamos acceso a tu ubicación para funcionar.");
            setIsTracking(false);
          },
          {
            enableHighAccuracy: true,
            timeout: 5000,
            maximumAge: 0,
          }
        );
    }

    return () => { 
        if(watchId !== null) navigator.geolocation.clearWatch(watchId); 
    };
  }, [isTestMode]);

  // --- Handlers ---

  const handleMapClick = (coords: Coordinates) => {
    if (isTestMode) {
      setUserLocation(coords);
    } else {
      setPendingZoneCoords(coords);
      setAppState(AppState.ADDING_ZONE);
    }
  };

  const handleSaveZone = (newZone: Zone) => {
    setZones((prev) => [...prev, newZone]);
    setAppState(AppState.MAP_VIEW);
    setPendingZoneCoords(null);
  };

  const handleCancelZone = () => {
    setAppState(AppState.MAP_VIEW);
    setPendingZoneCoords(null);
  };

  const handleManualDrag = () => {
    // If user moves map, stop auto centering
    if (isAutoCenterEnabled) setIsAutoCenterEnabled(false);
  };

  const handleRecenter = () => {
    // Force recenter
    setIsAutoCenterEnabled(true);
    // Trigger a slight update to force re-render if needed, though state change usually enough
    setUserLocation({...userLocation}); 
  };

  const togglePause = () => {
