import React, { useEffect, useRef, useState } from 'react';
import { Zone, Coordinates, PlayerState } from '../types';
import { calculateDistance } from '../constants';

interface AudioEngineProps {
  userLocation: Coordinates | null;
  zones: Zone[];
  isTracking: boolean;
  onStateChange: (state: PlayerState) => void;
  isPaused: boolean;
  onResetPause: () => void;
}

const AudioEngine: React.FC<AudioEngineProps> = ({ 
  userLocation, 
  zones, 
  isTracking, 
  onStateChange,
  isPaused,
  onResetPause
}) => {
  const [activeZoneId, setActiveZoneId] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Keep track of current metadata to restore state when unpausing
  const currentMeta = useRef<{
    trackName?: string;
    zoneName?: string;
  }>({});

  // Initialize audio element
  useEffect(() => {
    audioRef.current = new Audio();
    // No "onEnded" logic needed because ambient is always looped
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.src = "";
      }
    };
  }, [onStateChange]);

  // Handle Play/Pause toggle
  useEffect(() => {
    if (!audioRef.current) return;

    if (isPaused) {
      if (!audioRef.current.paused) {
        audioRef.current.pause();
        onStateChange({ 
            isPlaying: false,
            ...currentMeta.current 
        });
      }
    } else {
      // If unpaused and we have a valid source
      if (audioRef.current.src) {
         audioRef.current.play().catch(e => console.log("Resume failed", e));
         onStateChange({ 
            isPlaying: true,
            ...currentMeta.current
         });
      }
    }
  }, [isPaused, onStateChange]);

  useEffect(() => {
    if (!userLocation || !isTracking || !audioRef.current) return;

    if (zones.length === 0) return;

    // Find if we are inside any zone
    const currentZone = zones.find(zone => {
      const distance = calculateDistance(userLocation, zone.center);
      return distance <= zone.radius;
    });

    if (currentZone) {
      // WE ARE INSIDE A ZONE
      if (activeZoneId !== currentZone.id) {
        // Entering new zone
        console.log(`Entering zone: ${currentZone.name}`);

        // Reset manual pause for new location
        onResetPause();

        if (currentZone.music) {
          audioRef.current.src = currentZone.music.url;
          audioRef.current.loop = true; // ALWAYS LOOP AMBIENT MUSIC

          currentMeta.current = {
             trackName: currentZone.music.name,
             zoneName: currentZone.name,
          };

          audioRef.current.play().catch(e => console.log("Autoplay prevented:", e));

          onStateChange({
            isPlaying: true,
            ...currentMeta.current
          });
        } else {
          // Zone exists but no music configured (edge case if allowed)
          audioRef.current.pause();
          onStateChange({ isPlaying: false });
        }

        setActiveZoneId(currentZone.id);
      }
    } else {
      // WE ARE OUTSIDE ALL ZONES
      if (activeZoneId !== null) {
        // Just left a zone
        console.log(`Leaving zone (Stopping music)`);

        // Reset manual pause for exit event
        onResetPause();

        // Just stop playback. No exit music.
        audioRef.current.pause();
        audioRef.current.src = "";

        currentMeta.current = {};
        onStateChange({ isPlaying: false });

        setActiveZoneId(null);
      }
    }
  }, [userLocation, zones, isTracking, activeZoneId, onStateChange, onResetPause]);

  return (
    <div className="hidden">
      {/* Audio logic is headless */}
    </div>
  );
};

export default AudioEngine;

import React, { useEffect, useRef } from 'react';
import { MapContainer, TileLayer, Marker, Popup, Circle, useMap, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import { Coordinates, Zone } from '../types';
import { MAX_ZOOM } from '../constants';

// Fix Leaflet Default Icon
delete (L.Icon.Default.prototype as any)._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

// Detect drag to disable auto-centering
const MapEvents = ({ 
  onClick, 
  onDragStart 
}: { 
  onClick: (coords: Coordinates) => void;
  onDragStart: () => void;
}) => {
  useMapEvents({
    click(e) {
      onClick({ lat: e.latlng.lat, lng: e.latlng.lng });
    },
    dragstart() {
      onDragStart();
    }
  });
  return null;
};

// Component to handle recentering conditionally
const MapRecenter = ({ center, shouldRecenter }: { center: Coordinates, shouldRecenter: boolean }) => {
  const map = useMap();

  // Use a ref to prevent animation build-up
  const previousCenter = useRef<Coordinates>(center);

  useEffect(() => {
    if (shouldRecenter) {
        // Only fly to if significantly different to avoid jitter
        const dist = Math.abs(center.lat - previousCenter.current.lat) + Math.abs(center.lng - previousCenter.current.lng);
        if (dist > 0.0001) { // small threshold
            map.flyTo([center.lat, center.lng], map.getZoom(), { duration: 1 });
        } else {
             map.setView([center.lat, center.lng]);
        }
        previousCenter.current = center;
    }
  }, [center, map, shouldRecenter]);
  return null;
};

