              pathOptions={{ 
                color: '#6366f1', 
                fillColor: '#818cf8', 
                fillOpacity: 0.2,
                weight: 2
              }}
            />
            <Marker position={[zone.center.lat, zone.center.lng]}>
              <Popup>
                <div className="text-center">
                    <strong className="block text-lg">{zone.name}</strong>
                    <div className="text-xs text-gray-500 mt-1">
