              </Popup>
            </Marker>
          </React.Fragment>
        ))}

      </MapContainer>

      {/* Decorative overlay for "No Internet" hint */}
      <div className="absolute bottom-6 left-6 z-[400] bg-white/90 backdrop-blur text-black text-[10px] px-2 py-1 rounded shadow pointer-events-none opacity-60">
