                    <div className="w-1 bg-indigo-400 animate-pulse h-3 rounded-full"></div>
                    <div className="w-1 bg-indigo-400 animate-pulse h-6 rounded-full delay-75"></div>
                    <div className="w-1 bg-indigo-400 animate-pulse h-4 rounded-full delay-150"></div>
                </div>
             )}

             <button 
                onClick={onTogglePause}
                className="w-10 h-10 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center text-white transition-colors border border-white/10"
             >
                 {isPaused ? <Play size={20} className="ml-1" /> : <Pause size={20} />}
             </button>
        </div>
      </div>

      {/* CSS for custom spin if tailwind config doesn't have it */}
      <style>{`
        @keyframes spin-slow {
            from { transform: rotate(0deg); }
            to { transform: rotate(360deg); }
        }
        .animate-spin-slow {
            animation: spin-slow 4s linear infinite;
        }
      `}</style>
    </div>
  );
};

