import React, { useState, useEffect, useCallback } from 'react';
import { Coordinates, Zone, AppState, PlayerState } from './types';
import { DEFAULT_CENTER } from './constants';
import MapWrapper from './components/MapWrapper';
import ZoneModal from './components/ZoneModal';
import AudioEngine from './components/AudioEngine';
import MusicPlayer from './components/MusicPlayer';
import { MapPin, Plus, Music2, Navigation, AlertTriangle, FlaskConical, Move } from 'lucide-react';

const App: React.FC = () => {
  const [userLocation, setUserLocation] = useState<Coordinates>(DEFAULT_CENTER);
  const [zones, setZones] = useState<Zone[]>([]);
  const [appState, setAppState] = useState<AppState>(AppState.MAP_VIEW);
  const [pendingZoneCoords, setPendingZoneCoords] = useState<Coordinates | null>(null);

  // States for tracking and modes
  const [isTracking, setIsTracking] = useState(false);
  const [isTestMode, setIsTestMode] = useState(false);
  const [isAutoCenterEnabled, setIsAutoCenterEnabled] = useState(true);

  const [error, setError] = useState<string | null>(null);

  // Player State
  const [playerState, setPlayerState] = useState<PlayerState>({ isPlaying: false });
  const [isManualPaused, setIsManualPaused] = useState(false);

  // --- Geolocation Logic ---
  useEffect(() => {
    let watchId: number | null = null;

    if (isTestMode) {
        setIsTracking(false);
    } else {
        if (!navigator.geolocation) {
          setError("Geolocation is not supported by your browser");
          return;
        }

        setIsTracking(true);
        watchId = navigator.geolocation.watchPosition(
          (position) => {
            setUserLocation({
              lat: position.coords.latitude,
              lng: position.coords.longitude,
            });
            setError(null);
          },
          (err) => {
            console.error(err);
            setError("Necesitamos acceso a tu ubicación para funcionar.");
            setIsTracking(false);
          },
          {
            enableHighAccuracy: true,
            timeout: 5000,
            maximumAge: 0,
          }
        );
    }

    return () => { 
        if(watchId !== null) navigator.geolocation.clearWatch(watchId); 
    };
  }, [isTestMode]);

  // --- Handlers ---

  const handleMapClick = (coords: Coordinates) => {
    if (isTestMode) {
      setUserLocation(coords);
    } else {
      setPendingZoneCoords(coords);
      setAppState(AppState.ADDING_ZONE);
    }
  };

  const handleSaveZone = (newZone: Zone) => {
    setZones((prev) => [...prev, newZone]);
    setAppState(AppState.MAP_VIEW);
    setPendingZoneCoords(null);
  };

  const handleCancelZone = () => {
    setAppState(AppState.MAP_VIEW);
    setPendingZoneCoords(null);
  };

  const handleManualDrag = () => {
    // If user moves map, stop auto centering
    if (isAutoCenterEnabled) setIsAutoCenterEnabled(false);
  };

  const handleRecenter = () => {
    // Force recenter
    setIsAutoCenterEnabled(true);
    // Trigger a slight update to force re-render if needed, though state change usually enough
    setUserLocation({...userLocation}); 
  };

  const togglePause = () => {
      setIsManualPaused(!isManualPaused);
  };

  return (
    <div className="h-screen w-screen flex flex-col bg-[#121212] text-white relative overflow-hidden">

      {/* Header - Spotify Style */}
      <header className="absolute top-0 left-0 right-0 z-[500] p-4 pointer-events-none">
        <div className="flex justify-between items-start">
            <div className="bg-[#121212]/90 backdrop-blur-xl p-4 rounded-2xl shadow-2xl border border-white/5 pointer-events-auto">
                <h1 className="text-xl font-black text-[#1DB954] flex items-center gap-2 tracking-tight">
                    <Music2 fill="#1DB954" className="text-[#1DB954]" /> GeoGroove
                </h1>
                <div className="flex flex-col gap-1 mt-1">
                   <p className="text-xs text-[#B3B3B3] font-medium">
                      {zones.length} zonas activas
                   </p>
                   <div className="flex items-center gap-2">
                      {isTestMode ? (
                        <span className="text-[10px] font-bold text-black bg-[#1DB954] px-2 py-0.5 rounded-full uppercase tracking-wider">MODO PRUEBA</span>
                      ) : (
                        isTracking ? <span className="text-xs text-[#1DB954] font-bold">● GPS Activo</span> : <span className="text-xs text-[#FF4B4B] font-bold">● GPS Inactivo</span>
                      )}
                   </div>
                </div>
            </div>
        </div>
      </header>

      {/* Visual Music Player */}
      <MusicPlayer 
        playerState={playerState} 
        onTogglePause={togglePause}
        isPaused={isManualPaused}
      />

      {/* Map Area */}
      <div className="flex-1 relative">
        <MapWrapper 
          userLocation={userLocation} 
          zones={zones} 
          onMapClick={handleMapClick}
          isAutoCenterEnabled={isAutoCenterEnabled}
          onManualDrag={handleManualDrag}
        />

        {/* Free Move Indicator */}
        {!isAutoCenterEnabled && (
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-[400] pointer-events-none animate-in fade-in zoom-in duration-300">
                <div className="bg-[#181818]/90 text-white px-4 py-2 rounded-full text-sm font-bold border border-white/10 backdrop-blur-md flex items-center gap-2 shadow-2xl">
                    <Move size={14} className="text-[#1DB954]" /> Explorando
                </div>
            </div>
        )}
      </div>

      {/* Bottom Controls / Info - Spotify Style */}
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-[500] w-full max-w-sm px-4 pointer-events-none">
         {error && !isTestMode && (
             <div className="bg-[#FF4B4B] text-white p-3 rounded-lg mb-4 text-sm font-bold flex items-center gap-2 shadow-lg pointer-events-auto">
                 <AlertTriangle size={18} /> {error}
             </div>
         )}

         <div className="bg-[#181818] border border-white/5 p-5 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] pointer-events-auto transition-all">
            <p className="text-xs text-center text-[#B3B3B3] mb-4 font-bold uppercase tracking-widest">
                {isTestMode 
                  ? "🧪 Selecciona una ubicación" 
                  : isAutoCenterEnabled 
                     ? "Toca el mapa para agregar" 
                     : "Modo exploración libre"}
            </p>
            <div className="flex gap-3">
                <button 
                    onClick={handleRecenter}
                    className={`flex-1 py-3 rounded-full text-sm font-black uppercase tracking-wider transition-all duration-200 active:scale-95 flex items-center justify-center gap-2 ${
                        isAutoCenterEnabled 
                        ? "bg-[#282828] text-[#B3B3B3] cursor-not-allowed" 
                        : "bg-white text-black hover:bg-gray-200 shadow-lg"
                    }`}
                >
                    <Navigation size={16} fill="currentColor" /> Recenter
                </button>
                <button 
                    onClick={() => setIsTestMode(!isTestMode)}
                    className={`flex-1 py-3 rounded-full text-sm font-black uppercase tracking-wider transition-all duration-200 active:scale-95 flex items-center justify-center gap-2 ${
                        isTestMode 
                        ? "bg-white text-black hover:bg-gray-200" 
                        : "bg-[#1DB954] text-black hover:bg-[#1ed760] shadow-[0_8px_20px_rgba(29,185,84,0.3)]"
                    }`}
                >
                    <FlaskConical size={16} fill="currentColor" /> {isTestMode ? "Salir" : "Probar"}
                </button>
            </div>
         </div>
      </div>

      {/* Modals */}
      {appState === AppState.ADDING_ZONE && pendingZoneCoords && (
        <ZoneModal 
          location={pendingZoneCoords} 
          onSave={handleSaveZone} 
          onCancel={handleCancelZone} 
        />
      )}

      {/* Logic Components */}
      <AudioEngine 
        userLocation={userLocation}
        zones={zones}
        isTracking={isTracking || isTestMode}
        onStateChange={setPlayerState}
        isPaused={isManualPaused}
        onResetPause={() => setIsManualPaused(false)}
      />

    </div>
  );
};

export default App;

