import React, { useState } from 'react';
import { Coordinates, Zone, MusicTrack } from '../types';
import { X, Music, Upload, Loader2, Sparkles } from 'lucide-react';
import { generateZoneDetails } from '../services/geminiService';

interface ZoneModalProps {
  location: Coordinates;
  onSave: (zone: Zone) => void;
  onCancel: () => void;
}

const ZoneModal: React.FC<ZoneModalProps> = ({ location, onSave, onCancel }) => {
  const [name, setName] = useState('');
  const [radius, setRadius] = useState(50);
  const [musicFile, setMusicFile] = useState<File | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setMusicFile(e.target.files[0]);
    }
  };

  const handleGeminiSuggestion = async () => {
    setIsGenerating(true);
    try {
      const details = await generateZoneDetails(location.lat, location.lng);
      setName(details.suggestedName);
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = () => {
    if (!name) return;

    const newZone: Zone = {
      id: Date.now().toString(),
      name,
      center: location,
      radius,
      music: musicFile ? {
        file: musicFile,
        url: URL.createObjectURL(musicFile),
        name: musicFile.name
      } : undefined,
    };

    onSave(newZone);
  };

  return (
    <div className="fixed inset-0 z-[1000] flex items-end sm:items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-[#121212] border border-white/5 w-full max-w-md rounded-[32px] p-8 shadow-[0_20px_60px_rgba(0,0,0,0.8)] flex flex-col gap-6 animate-in slide-in-from-bottom-20 duration-500">

        <div className="flex justify-between items-center">
          <h2 className="text-2xl font-black text-white tracking-tighter">
            Nueva Zona
          </h2>
          <button onClick={onCancel} className="p-2 hover:bg-[#282828] rounded-full text-[#B3B3B3] transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="space-y-6">

          {/* Name Input with AI Gen */}
          <div className="space-y-2">
            <label className="text-[10px] text-[#B3B3B3] font-black uppercase tracking-[0.2em]">Identificador</label>
            <div className="flex gap-2">
              <input 
                type="text" 
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Nombre de la ubicación"
                className="flex-1 bg-[#282828] border-none rounded-lg p-4 text-white placeholder:text-[#535353] focus:ring-2 focus:ring-[#1DB954] outline-none font-bold"
              />
              <button 
                onClick={handleGeminiSuggestion}
                disabled={isGenerating}
                className="bg-[#282828] p-4 rounded-lg text-[#1DB954] hover:bg-[#3e3e3e] disabled:opacity-50 transition-all border border-white/5"
                title="Sugerir nombre con IA"
              >
                {isGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" fill="currentColor" />}
              </button>
            </div>
          </div>

          {/* Radius Slider */}
          <div className="space-y-3">
            <label className="text-[10px] text-[#B3B3B3] font-black uppercase tracking-[0.2em] flex justify-between">
              <span>Rango Geográfico</span>
              <span className="text-[#1DB954]">{radius}m</span>
            </label>
            <input 
              type="range" 
              min="10" 
              max="200" 
              step="10"
              value={radius} 
              onChange={(e) => setRadius(Number(e.target.value))}
              className="w-full h-1 bg-[#282828] rounded-lg appearance-none cursor-pointer accent-[#1DB954]"
            />
          </div>

          {/* Ambient Music */}
          <div className="bg-[#181818] p-6 rounded-2xl border border-white/5 space-y-4">
            <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-[#1DB954] rounded-lg flex items-center justify-center">
                    <Music className="text-black w-5 h-5" />
                </div>
                <div>
                    <h4 className="text-sm font-black text-white uppercase tracking-tight">Sonido Ambiente</h4>
                    <p className="text-[10px] text-[#B3B3B3] font-bold">Música en bucle dentro de la zona</p>
                </div>
            </div>

            <div className="relative group">
                <input 
                  type="file" 
                  accept="audio/mp3,audio/*"
                  onChange={handleFileChange}
                  className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                />
                <div className="flex items-center gap-3 p-4 bg-[#282828] rounded-full border border-transparent group-hover:border-[#1DB954] transition-all text-center justify-center">
                  <Upload className="w-4 h-4 text-[#B3B3B3]" />
                  <div className="truncate text-xs font-bold text-white">
                    {musicFile ? musicFile.name : "Subir archivo MP3"}
                  </div>
                </div>
            </div>
          </div>

        </div>

        <button 
          onClick={handleSave}
          disabled={!name || !musicFile}
          className="w-full bg-[#1DB954] hover:bg-[#1ed760] text-black font-black py-4 rounded-full transition-all duration-200 disabled:opacity-30 disabled:grayscale active:scale-95 shadow-xl shadow-[#1DB954]/20 uppercase tracking-widest text-sm"
        >
          Guardar Cambios
        </button>

      </div>
    </div>
  );
};

