import AudioEngine from './components/AudioEngine';
import MusicPlayer from './components/MusicPlayer';
import { Navigation, AlertTriangle, FlaskConical, Move, Settings } from 'lucide-react';

const App: React.FC = () => {
  const [userLocation, setUserLocation] = useState<Coordinates>(DEFAULT_CENTER);
  const [zones, setZones] = useState<Zone[]>([]);
  const [appState, setAppState] = useState<AppState>(AppState.MAP_VIEW);
  const [pendingZoneCoords, setPendingZoneCoords] = useState<Coordinates | null>(null);

  // Settings State
  const [settings, setSettings] = useState<AppSettings>({
    primaryColor: '#1DB954',
    language: 'es',
    userName: 'Usuario GeoGroove',
    selectedDeviceId: 'default',
    volume: 0.8
  });

  // States for tracking and modes
  const [isTracking, setIsTracking] = useState(false);
  const [isTestMode, setIsTestMode] = useState(false);
  const [isAutoCenterEnabled, setIsAutoCenterEnabled] = useState(true);

  const [error, setError] = useState<string | null>(null);

  // Player State
  const [playerState, setPlayerState] = useState<PlayerState>({ isPlaying: false });
  const [isManualPaused, setIsManualPaused] = useState(false);

  // Apply primary color to document for CSS variables
  useEffect(() => {
    document.documentElement.style.setProperty('--primary-color', settings.primaryColor);
  }, [settings.primaryColor]);

  // --- Geolocation Logic ---
  useEffect(() => {
    let watchId: number | null = null;

    if (isTestMode) {
        setIsTracking(false);
    } else {
        if (!navigator.geolocation) {
          setError("Geolocation is not supported by your browser");
          return;
        }

        setIsTracking(true);
        watchId = navigator.geolocation.watchPosition(
          (position) => {
            setUserLocation({
              lat: position.coords.latitude,
              lng: position.coords.longitude,
            });
            setError(null);
          },
          (err) => {
            console.error(err);
            setError(settings.language === 'en' ? "We need location access to work." : "Necesitamos acceso a tu ubicación para funcionar.");
            setIsTracking(false);
          },
          {
            enableHighAccuracy: true,
            timeout: 5000,
            maximumAge: 0,
          }
        );
    }

    return () => { 
        if(watchId !== null) navigator.geolocation.clearWatch(watchId); 
    };
  }, [isTestMode, settings.language]);

  const handleMapClick = (coords: Coordinates) => {
    if (isTestMode) {
      setUserLocation(coords);
    } else {
      setPendingZoneCoords(coords);
      setAppState(AppState.ADDING_ZONE);
    }
  };

  const handleSaveZone = (newZone: Zone) => {
    setZones((prev) => [...prev, newZone]);
    setAppState(AppState.MAP_VIEW);
    setPendingZoneCoords(null);
  };

  const handleCancelZone = () => {
    setAppState(AppState.MAP_VIEW);
    setPendingZoneCoords(null);
  };

  const handleManualDrag = () => {
    if (isAutoCenterEnabled) setIsAutoCenterEnabled(false);
  };

  const handleRecenter = () => {
    setIsAutoCenterEnabled(true);
    setUserLocation({...userLocation}); 
  };

  const togglePause = () => {
      setIsManualPaused(!isManualPaused);
  };

  const translations = {
    es: { zones: 'zonas activas', test: 'MODO PRUEBA', gpsOn: 'GPS Activo', gpsOff: 'GPS Inactivo', exploring: 'Explorando', tap: 'Toca el mapa para agregar', explore: 'Modo exploración libre', recenter: 'Recentrar', testBtn: 'Probar', testOut: 'Salir', testPick: 'Selecciona una ubicación' },
    en: { zones: 'active zones', test: 'TEST MODE', gpsOn: 'GPS Active', gpsOff: 'GPS Inactive', exploring: 'Exploring', tap: 'Tap map to add', explore: 'Free exploration mode', recenter: 'Recenter', testBtn: 'Test', testOut: 'Exit', testPick: 'Select a location' },
    pt: { zones: 'zonas ativas', test: 'MODO TESTE', gpsOn: 'GPS Ativo', gpsOff: 'GPS Inativo', exploring: 'Explorando', tap: 'Toque no mapa para adicionar', explore: 'Modo exploração libre', recenter: 'Recentrar', testBtn: 'Testar', testOut: 'Sair', testPick: 'Selecione um local' }
  }[settings.language];

  return (
    <div className="h-screen w-screen flex flex-col bg-[#121212] text-white relative overflow-hidden">
      <style>{`
        :root { --primary-color: #1DB954; }
        .text-primary { color: var(--primary-color); }
        .bg-primary { background-color: var(--primary-color); }
        .border-primary { border-color: var(--primary-color); }
        .ring-primary { --tw-ring-color: var(--primary-color); }
      `}</style>

      {/* Header */}
      <header className="absolute top-0 left-0 right-0 z-[500] p-4 flex justify-between items-start pointer-events-none">
        <div className="bg-[#121212]/90 backdrop-blur-xl p-4 rounded-2xl shadow-2xl border border-white/5 pointer-events-auto">
            <h1 className="text-xl font-black text-primary flex items-center gap-3 tracking-tight">
                <img src={getAppIcon(settings.primaryColor)} alt="GeoGroove Icon" className="w-8 h-8 object-contain" /> 
                GeoGroove
            </h1>
            <div className="flex flex-col gap-1 mt-1">
               <p className="text-xs text-[#B3B3B3] font-medium">
                  {zones.length} {translations.zones}
               </p>
               <div className="flex items-center gap-2">
                  {isTestMode ? (
                    <span className="text-[10px] font-bold text-black bg-primary px-2 py-0.5 rounded-full uppercase tracking-wider">{translations.test}</span>
                  ) : (
                    isTracking ? <span className="text-xs text-primary font-bold">● {translations.gpsOn}</span> : <span className="text-xs text-[#FF4B4B] font-bold">● {translations.gpsOff}</span>
                  )}
               </div>
            </div>
        </div>

        {/* Settings Trigger */}
        <button 
          onClick={() => setAppState(AppState.SETTINGS)}
          className="bg-[#121212]/90 backdrop-blur-xl p-4 rounded-2xl shadow-2xl border border-white/5 pointer-events-auto hover:bg-[#282828] transition-colors"
        >
          <Settings className="w-6 h-6 text-white" />
        </button>
      </header>

      {/* Visual Music Player */}
      <MusicPlayer 
        playerState={playerState} 
        onTogglePause={togglePause}
        isPaused={isManualPaused}
        settings={settings}
      />

      {/* Map Area */}
      <div className="flex-1 relative">
        <MapWrapper 
          userLocation={userLocation} 
          zones={zones} 
          onMapClick={handleMapClick}
          isAutoCenterEnabled={isAutoCenterEnabled}
          onManualDrag={handleManualDrag}
        />

        {!isAutoCenterEnabled && (
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-[400] pointer-events-none animate-in fade-in zoom-in duration-300">
                <div className="bg-[#181818]/90 text-white px-4 py-2 rounded-full text-sm font-bold border border-white/10 backdrop-blur-md flex items-center gap-2 shadow-2xl">
                    <Move size={14} className="text-primary" /> {translations.exploring}
                </div>
            </div>
        )}
      </div>

      {/* Bottom Controls */}
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-[500] w-full max-w-sm px-4 pointer-events-none">
         {error && !isTestMode && (
             <div className="bg-[#FF4B4B] text-white p-3 rounded-lg mb-4 text-sm font-bold flex items-center gap-2 shadow-lg pointer-events-auto">
                 <AlertTriangle size={18} /> {error}
