         )}

         <div className="bg-[#181818] border border-white/5 p-5 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] pointer-events-auto transition-all">
            <p className="text-xs text-center text-[#B3B3B3] mb-4 font-bold uppercase tracking-widest">
                {isTestMode 
                  ? `🧪 ${translations.testPick}` 
                  : isAutoCenterEnabled 
                     ? translations.tap 
                     : translations.explore}
            </p>
            <div className="flex gap-3">
                <button 
                    onClick={handleRecenter}
                    className={`flex-1 py-3 rounded-full text-sm font-black uppercase tracking-wider transition-all duration-200 active:scale-95 flex items-center justify-center gap-2 ${
                        isAutoCenterEnabled 
                        ? "bg-[#282828] text-[#B3B3B3] cursor-not-allowed" 
                        : "bg-white text-black hover:bg-gray-200 shadow-lg"
                    }`}
                >
                    <Navigation size={16} fill="currentColor" /> {translations.recenter}
                </button>
                <button 
                    onClick={() => setIsTestMode(!isTestMode)}
                    className={`flex-1 py-3 rounded-full text-sm font-black uppercase tracking-wider transition-all duration-200 active:scale-95 flex items-center justify-center gap-2 ${
                        isTestMode 
                        ? "bg-white text-black hover:bg-gray-200" 
                        : "bg-primary text-black hover:brightness-110 shadow-[0_8px_20px_rgba(0,0,0,0.3)]"
                    }`}
                >
                    <FlaskConical size={16} fill="currentColor" /> {isTestMode ? translations.testOut : translations.testBtn}
                </button>
            </div>
         </div>
      </div>

      {/* Modals */}
      {appState === AppState.ADDING_ZONE && pendingZoneCoords && (
        <ZoneModal 
          location={pendingZoneCoords} 
          onSave={handleSaveZone} 
          onCancel={handleCancelZone} 
        />
      )}

      {appState === AppState.SETTINGS && (
        <SettingsModal 
          settings={settings}
          onUpdate={setSettings}
          onClose={() => setAppState(AppState.MAP_VIEW)}
        />
      )}

      {/* Logic Components */}
      <AudioEngine 
        userLocation={userLocation}
        zones={zones}
        isTracking={isTracking || isTestMode}
        onStateChange={setPlayerState}
        isPaused={isManualPaused}
        onResetPause={() => setIsManualPaused(false)}
        volume={settings.volume}
      />

    </div>
  );
};

