        </div>

        <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
          {activeTab === 'root' && (
            <div className="space-y-4">
              <div className="p-4 bg-primary/10 rounded-3xl border border-primary/20 flex items-center gap-4 mb-4">
                 <div className="w-16 h-16 rounded-full overflow-hidden bg-[#282828] border-2 border-primary shrink-0">
                    {settings.userImage ? (
