                    ) : (
                      <div className="w-full h-full flex items-center justify-center text-[#B3B3B3]">
                        <User size={32} />
                      </div>
                    )}
                 </div>
                 <div className="min-w-0 flex-1">
                    <h3 className="font-bold text-white truncate">{settings.userName}</h3>
                    <button 
                      onClick={() => setActiveTab('profile')}
                      className="text-[10px] font-black uppercase text-primary tracking-widest mt-1"
                    >
