          {activeTab === 'appearance' && (
            <div className="space-y-6">
              <div className="bg-[#282828] p-6 rounded-3xl">
                <label className="text-xs font-black uppercase text-[#B3B3B3] tracking-widest block mb-4">{t.accentColor}</label>
                <div className="flex flex-wrap gap-3">
                  {colors.map(c => (
                    <button
