                      onClick={() => onUpdate({ ...settings, primaryColor: c })}
                      className={`w-10 h-10 rounded-full border-4 transition-transform active:scale-90 ${settings.primaryColor === c ? 'border-white scale-110' : 'border-transparent'}`}
