                      <span>0%</span>
                      <span>50%</span>
                      <span>100%</span>
                    </div>
                  </div>
               </div>

               <div className="flex gap-4">
                  <button 
                    onClick={() => onUpdate({ ...settings, volume: 0 })}
                    className="flex-1 py-4 bg-[#282828] text-[#B3B3B3] hover:text-white rounded-2xl font-black text-xs uppercase tracking-widest transition-all"
                  >
                    {t.mute}
                  </button>
                  <button 
                    onClick={() => onUpdate({ ...settings, volume: 1 })}
                    className="flex-1 py-4 bg-[#282828] text-primary rounded-2xl font-black text-xs uppercase tracking-widest transition-all border border-primary/10"
                  >
