          )}
        </div>

        <div className="p-6 bg-[#181818] border-t border-white/5">
           <button 
            onClick={activeTab === 'root' ? onClose : () => setActiveTab('root')}
            className="w-full py-4 bg-primary text-black font-black rounded-full uppercase tracking-widest text-xs shadow-lg shadow-primary/20 active:scale-95 transition-all"
           >
             {activeTab === 'root' ? t.close : t.back}
