import React, { useState } from 'react';
import { PlayerState, AppSettings } from '../types';
import { getAppIcon } from '../constants';
import { Volume2, Pause, Play, VolumeX, Volume1 } from 'lucide-react';

interface MusicPlayerProps {
  playerState: PlayerState;
  onTogglePause: () => void;
  isPaused: boolean;
  settings: AppSettings;
  onVolumeChange: (volume: number) => void;
}

const MusicPlayer: React.FC<MusicPlayerProps> = ({ 
  playerState, 
  onTogglePause, 
  isPaused, 
  settings,
  onVolumeChange
}) => {
  const [showVolumeSlider, setShowVolumeSlider] = useState(false);

  if (!playerState.isPlaying && !isPaused) return null;
  if (!playerState.trackName) return null;

  return (
    <div className="fixed top-24 left-4 right-4 z-[450] animate-in slide-in-from-top-5 fade-in duration-500">
      <div className="bg-[#282828] border border-white/5 p-3 rounded-2xl shadow-[0_15px_35px_rgba(0,0,0,0.6)] flex items-center gap-3 relative overflow-hidden group backdrop-blur-md">

        {/* Background Glow */}
        <div className={`absolute top-0 left-0 w-full h-full transition-opacity duration-500 ${isPaused ? 'opacity-0' : 'opacity-100'}`} style={{ backgroundColor: `${settings.primaryColor}0D` }}></div>

        {/* Progress bar mock */}
        <div className="absolute bottom-0 left-0 h-1 bg-white/10 w-full">
            <div className={`h-full transition-all duration-500 ${isPaused ? 'w-1/3' : 'w-2/3 animate-pulse'}`} style={{ backgroundColor: settings.primaryColor }}></div>
        </div>

        {/* User Image or Icon */}
        <div className="relative shrink-0">
            <div className="w-12 h-12 rounded-xl bg-[#181818] border border-white/10 flex items-center justify-center shadow-lg overflow-hidden">
                {settings.userImage ? (
                  <img src={settings.userImage} alt="User profile" className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center">
                    <img src={getAppIcon(settings.primaryColor)} alt="GeoGroove Icon" className="w-10 h-10 object-contain" />
                  </div>
                )}
            </div>
            {!isPaused && (
                <div className="absolute -top-1 -right-1 w-5 h-5 rounded-full border-2 border-[#282828] flex items-center justify-center" style={{ backgroundColor: settings.primaryColor }}>
                    <Volume2 size={10} className="text-black" />
                </div>
            )}
        </div>

        {/* Text Info */}
        <div className="flex-1 min-w-0">
            <h3 className="text-white font-bold text-sm truncate tracking-tight">
                {String(playerState.trackName || "Reproduciendo...")}
            </h3>
            <p className="text-[#B3B3B3] text-[10px] truncate font-black uppercase tracking-widest opacity-70">
                {String(playerState.zoneName || "Ubicación")}
            </p>
        </div>

        {/* Controls */}
        <div className="flex items-center gap-1 shrink-0 bg-black/20 p-1 rounded-full border border-white/5">
             <div className="flex items-center gap-2 px-2 group/volume relative">
                <button 
                  onClick={() => setShowVolumeSlider(!showVolumeSlider)}
                  className={`p-2 rounded-full transition-colors ${showVolumeSlider ? 'text-primary' : 'text-[#B3B3B3] hover:text-white'}`}
                >
                  {settings.volume === 0 ? <VolumeX size={18} /> : settings.volume < 0.5 ? <Volume1 size={18} /> : <Volume2 size={18} />}
                </button>

                {/* Volume Slider - Expandable */}
                <div className={`flex items-center transition-all duration-300 overflow-hidden ${showVolumeSlider ? 'w-24 opacity-100' : 'w-0 opacity-0'}`}>
                  <input 
                    type="range"
                    min="0"
                    max="1"
                    step="0.01"
                    value={settings.volume}
                    onChange={(e) => onVolumeChange(parseFloat(e.target.value))}
                    className="w-20 h-1 bg-white/20 rounded-full appearance-none cursor-pointer accent-primary"
                  />
                </div>
             </div>

             <button 
                onClick={onTogglePause}
                className="w-10 h-10 rounded-full flex items-center justify-center text-white transition-all hover:scale-110 active:scale-90 bg-white/5"
             >
                 {isPaused ? <Play size={20} fill="white" /> : <Pause size={20} fill="white" />}
             </button>
        </div>
      </div>
    </div>
  );
};

export default MusicPlayer;

import React, { useState, useEffect } from 'react';
import { Coordinates, Zone, AppState, PlayerState, AppSettings } from './types';
import { DEFAULT_CENTER, getAppIcon } from './constants';
import MapWrapper from './components/MapWrapper';
import ZoneModal from './components/ZoneModal';
import SettingsModal from './components/SettingsModal';
import AudioEngine from './components/AudioEngine';
import MusicPlayer from './components/MusicPlayer';
import { Navigation, AlertTriangle, FlaskConical, Move, Settings } from 'lucide-react';

const App: React.FC = () => {
  const [userLocation, setUserLocation] = useState<Coordinates>(DEFAULT_CENTER);
  const [zones, setZones] = useState<Zone[]>([]);
  const [appState, setAppState] = useState<AppState>(AppState.MAP_VIEW);
  const [pendingZoneCoords, setPendingZoneCoords] = useState<Coordinates | null>(null);

  // Settings State
  const [settings, setSettings] = useState<AppSettings>({
    primaryColor: '#1DB954',
    language: 'es',
    userName: 'Usuario GeoGroove',
    selectedDeviceId: 'default',
    volume: 0.8
  });

  // States for tracking and modes
  const [isTracking, setIsTracking] = useState(false);
  const [isTestMode, setIsTestMode] = useState(false);
  const [isAutoCenterEnabled, setIsAutoCenterEnabled] = useState(true);

  const [error, setError] = useState<string | null>(null);

  // Player State
  const [playerState, setPlayerState] = useState<PlayerState>({ isPlaying: false });
  const [isManualPaused, setIsManualPaused] = useState(false);

  // Apply primary color to document for CSS variables
  useEffect(() => {
    document.documentElement.style.setProperty('--primary-color', settings.primaryColor);
  }, [settings.primaryColor]);

  // --- Geolocation Logic ---
  useEffect(() => {
    let watchId: number | null = null;

    if (isTestMode) {
        setIsTracking(false);
    } else {
        if (!navigator.geolocation) {
          setError("Geolocation is not supported by your browser");
          return;
        }

        setIsTracking(true);
        watchId = navigator.geolocation.watchPosition(
          (position) => {
            setUserLocation({
              lat: position.coords.latitude,
              lng: position.coords.longitude,
            });
            setError(null);
          },
          (err) => {
            console.error(err);
            setError(settings.language === 'en' ? "We need location access to work." : "Necesitamos acceso a tu ubicación para funcionar.");
            setIsTracking(false);
          },
          {
            enableHighAccuracy: true,
            timeout: 5000,
            maximumAge: 0,
          }
        );
    }

    return () => { 
        if(watchId !== null) navigator.geolocation.clearWatch(watchId); 
    };
  }, [isTestMode, settings.language]);

  const handleMapClick = (coords: Coordinates) => {
    if (isTestMode) {
      setUserLocation(coords);
    } else {
      setPendingZoneCoords(coords);
      setAppState(AppState.ADDING_ZONE);
    }
  };

  const handleSaveZone = (newZone: Zone) => {
    setZones((prev) => [...prev, newZone]);
    setAppState(AppState.MAP_VIEW);
    setPendingZoneCoords(null);
  };

  const handleDeleteZone = (id: string) => {
    setZones((prev) => prev.filter(z => z.id !== id));
  };

  const handleUpdateZone = (updatedZone: Zone) => {
    setZones((prev) => prev.map(z => z.id === updatedZone.id ? updatedZone : z));
  };

  const handleCancelZone = () => {
    setAppState(AppState.MAP_VIEW);
    setPendingZoneCoords(null);
  };

  const handleManualDrag = () => {
    if (isAutoCenterEnabled) setIsAutoCenterEnabled(false);
  };

  const handleRecenter = () => {
    setIsAutoCenterEnabled(true);
    setUserLocation({...userLocation}); 
  };

  const togglePause = () => {
      setIsManualPaused(!isManualPaused);
  };

  const handleVolumeChange = (newVolume: number) => {
    setSettings(prev => ({ ...prev, volume: newVolume }));
  };

  const translations = {
    es: { zones: 'zonas activas', test: 'MODO PRUEBA', gpsOn: 'GPS Activo', gpsOff: 'GPS Inactivo', exploring: 'Explorando', tap: 'Toca el mapa para agregar', explore: 'Modo exploración libre', recenter: 'Recentrar', testBtn: 'Probar', testOut: 'Salir', testPick: 'Selecciona una ubicación' },
    en: { zones: 'active zones', test: 'TEST MODE', gpsOn: 'GPS Active', gpsOff: 'GPS Inactive', exploring: 'Exploring', tap: 'Tap map to add', explore: 'Free exploration mode', recenter: 'Recenter', testBtn: 'Test', testOut: 'Exit', testPick: 'Select a location' },
    pt: { zones: 'zonas ativas', test: 'MODO TESTE', gpsOn: 'GPS Ativo', gpsOff: 'GPS Inativo', exploring: 'Explorando', tap: 'Toque no mapa para adicionar', explore: 'Modo exploração libre', recenter: 'Recentrar', testBtn: 'Testar', testOut: 'Sair', testPick: 'Selecione um local' }
  }[settings.language];

  return (
    <div className="h-screen w-screen flex flex-col bg-[#121212] text-white relative overflow-hidden">
      <style>{`
        :root { --primary-color: #1DB954; }
        .text-primary { color: var(--primary-color); }
        .bg-primary { background-color: var(--primary-color); }
        .border-primary { border-color: var(--primary-color); }
        .ring-primary { --tw-ring-color: var(--primary-color); }
      `}</style>

      {/* Header */}
      <header className="absolute top-0 left-0 right-0 z-[500] p-4 flex justify-between items-start pointer-events-none">
        <div className="bg-[#121212]/90 backdrop-blur-xl p-4 rounded-2xl shadow-2xl border border-white/5 pointer-events-auto">
            <h1 className="text-xl font-black text-primary flex items-center gap-3 tracking-tight">
                <img src={getAppIcon(settings.primaryColor)} alt="GeoGroove Icon" className="w-8 h-8 object-contain" /> 
                GeoGroove
            </h1>
            <div className="flex flex-col gap-1 mt-1">
               <p className="text-xs text-[#B3B3B3] font-medium">
                  {zones.length} {translations.zones}
               </p>
               <div className="flex items-center gap-2">
                  {isTestMode ? (
                    <span className="text-[10px] font-bold text-black bg-primary px-2 py-0.5 rounded-full uppercase tracking-wider">{translations.test}</span>
                  ) : (
                    isTracking ? <span className="text-xs text-primary font-bold">● {translations.gpsOn}</span> : <span className="text-xs text-[#FF4B4B] font-bold">● {translations.gpsOff}</span>
                  )}
               </div>
            </div>
        </div>

        {/* Settings Trigger */}
        <button 
          onClick={() => setAppState(AppState.SETTINGS)}
          className="bg-[#121212]/90 backdrop-blur-xl p-4 rounded-2xl shadow-2xl border border-white/5 pointer-events-auto hover:bg-[#282828] transition-colors"
        >
          <Settings className="w-6 h-6 text-white" />
        </button>
      </header>

      {/* Visual Music Player */}
      <MusicPlayer 
        playerState={playerState} 
        onTogglePause={togglePause}
        isPaused={isManualPaused}
        settings={settings}
        onVolumeChange={handleVolumeChange}
      />

      {/* Map Area */}
      <div className="flex-1 relative">
        <MapWrapper 
          userLocation={userLocation} 
          zones={zones} 
          onMapClick={handleMapClick}
          isAutoCenterEnabled={isAutoCenterEnabled}
          onManualDrag={handleManualDrag}
        />

        {!isAutoCenterEnabled && (
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-[400] pointer-events-none animate-in fade-in zoom-in duration-300">
                <div className="bg-[#181818]/90 text-white px-4 py-2 rounded-full text-sm font-bold border border-white/10 backdrop-blur-md flex items-center gap-2 shadow-2xl">
                    <Move size={14} className="text-primary" /> {translations.exploring}
                </div>
            </div>
        )}
      </div>

      {/* Bottom Controls */}
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-[500] w-full max-w-sm px-4 pointer-events-none">
         {error && !isTestMode && (
             <div className="bg-[#FF4B4B] text-white p-3 rounded-lg mb-4 text-sm font-bold flex items-center gap-2 shadow-lg pointer-events-auto">
                 <AlertTriangle size={18} /> {error}
             </div>
         )}

         <div className="bg-[#181818] border border-white/5 p-5 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] pointer-events-auto transition-all">
            <p className="text-xs text-center text-[#B3B3B3] mb-4 font-bold uppercase tracking-widest">
                {isTestMode 
                  ? `🧪 ${translations.testPick}` 
                  : isAutoCenterEnabled 
                     ? translations.tap 
                     : translations.explore}
            </p>
            <div className="flex gap-3">
                <button 
                    onClick={handleRecenter}
                    className={`flex-1 py-3 rounded-full text-sm font-black uppercase tracking-wider transition-all duration-200 active:scale-95 flex items-center justify-center gap-2 ${
                        isAutoCenterEnabled 
                        ? "bg-[#282828] text-[#B3B3B3] cursor-not-allowed" 
                        : "bg-white text-black hover:bg-gray-200 shadow-lg"
                    }`}
                >
                    <Navigation size={16} fill="currentColor" /> {translations.recenter}
                </button>
                <button 
                    onClick={() => setIsTestMode(!isTestMode)}
                    className={`flex-1 py-3 rounded-full text-sm font-black uppercase tracking-wider transition-all duration-200 active:scale-95 flex items-center justify-center gap-2 ${
                        isTestMode 
                        ? "bg-white text-black hover:bg-gray-200" 
                        : "bg-primary text-black hover:brightness-110 shadow-[0_8px_20px_rgba(0,0,0,0.3)]"
                    }`}
                >
                    <FlaskConical size={16} fill="currentColor" /> {isTestMode ? translations.testOut : translations.testBtn}
                </button>
            </div>
         </div>
      </div>

      {/* Modals */}
      {appState === AppState.ADDING_ZONE && pendingZoneCoords && (
        <ZoneModal 
          location={pendingZoneCoords} 
          onSave={handleSaveZone} 
          onCancel={handleCancelZone} 
        />
      )}

      {appState === AppState.SETTINGS && (
        <SettingsModal 
          settings={settings}
          onUpdate={setSettings}
          onClose={() => setAppState(AppState.MAP_VIEW)}
          zones={zones}
          onDeleteZone={handleDeleteZone}
          onUpdateZone={handleUpdateZone}
        />
      )}

      {/* Logic Components */}
      <AudioEngine 
        userLocation={userLocation}
        zones={zones}
        isTracking={isTracking || isTestMode}
        onStateChange={setPlayerState}
        isPaused={isManualPaused}
        onResetPause={() => setIsManualPaused(false)}
        volume={settings.volume}
      />

    </div>
  );
};

