  location: Coordinates;
  onSave: (zone: Zone) => void;
  onCancel: () => void;
}

const ZoneModal: React.FC<ZoneModalProps> = ({ location, onSave, onCancel }) => {
  const [name, setName] = useState('');
  const [radius, setRadius] = useState(50);
  const [musicFile, setMusicFile] = useState<File | null>(null);
  const [coverImage, setCoverImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setMusicFile(e.target.files[0]);
    }
  };

  const handleCoverChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setCoverImage(event.target?.result as string);
      };
      reader.readAsDataURL(e.target.files[0]);
    }
  };

  const handleGeminiSuggestion = async () => {
    setIsGenerating(true);
    try {
      const details = await generateZoneDetails(location.lat, location.lng);
      setName(details.suggestedName);
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = () => {
    if (!name) return;

    const newZone: Zone = {
      id: Date.now().toString(),
      name,
      center: location,
      radius,
      music: musicFile ? {
        file: musicFile,
        url: URL.createObjectURL(musicFile),
        name: musicFile.name,
        coverUrl: coverImage || undefined
      } : undefined,
