import React, { useEffect, useRef, useState } from 'react';
import { Zone, Coordinates, PlayerState } from '../types';
import { calculateDistance } from '../constants';

interface AudioEngineProps {
  userLocation: Coordinates | null;
  zones: Zone[];
  isTracking: boolean;
  onStateChange: (state: PlayerState) => void;
  isPaused: boolean;
  onResetPause: () => void;
  volume: number;
}

const AudioEngine: React.FC<AudioEngineProps> = ({ 
  userLocation, 
  zones, 
  isTracking, 
  onStateChange,
  isPaused,
  onResetPause,
  volume
}) => {
  const [activeZoneId, setActiveZoneId] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const currentMeta = useRef<{
    trackName?: string;
    zoneName?: string;
    coverUrl?: string;
  }>({});

  useEffect(() => {
    audioRef.current = new Audio();
    audioRef.current.volume = volume;
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.src = "";
      }
    };
  }, []);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume;
    }
  }, [volume]);

  // Handle manual pause from UI
  useEffect(() => {
    if (!audioRef.current) return;

    if (isPaused) {
      audioRef.current.pause();
      onStateChange({ 
          isPlaying: false,
          ...currentMeta.current 
      });
    } else if (audioRef.current.src && activeZoneId) {
      audioRef.current.play().catch(e => console.log("Resume failed", e));
      onStateChange({ 
          isPlaying: true,
          ...currentMeta.current
      });
    }
  }, [isPaused, onStateChange]);

  // Handle location and zone membership
  useEffect(() => {
    if (!userLocation || !isTracking || !audioRef.current) return;

    // 1. Find the current zone the user is in
    const currentZone = zones.find(zone => {
      const distance = calculateDistance(userLocation, zone.center);
      return distance <= zone.radius;
    });

    // 2. Logic for when the user is currently in a zone
    if (currentZone) {
      if (activeZoneId !== currentZone.id) {
        // We entered a NEW zone
        console.log(`Entering zone: ${currentZone.name}`);

        // Reset manual pause state for the new location experience
        onResetPause();

        if (currentZone.music) {
          audioRef.current.src = currentZone.music.url;
          audioRef.current.loop = true;

          currentMeta.current = {
             trackName: currentZone.music.name,
             zoneName: currentZone.name,
             coverUrl: currentZone.music.coverUrl
          };

          // Only start playing if not explicitly paused (onResetPause sets isPaused=false, but we check to be safe)
          audioRef.current.play().catch(e => console.log("Playback failed:", e));

          onStateChange({
            isPlaying: true,
            ...currentMeta.current
          });
        }
        setActiveZoneId(currentZone.id);
      }
    } else {
      // 3. Logic for when the user is outside all zones or the active zone was deleted
      if (activeZoneId !== null) {
        console.log(`Exiting zone/Zone deleted (Stopping music)`);

        audioRef.current.pause();
        audioRef.current.src = "";

        currentMeta.current = {};
        onStateChange({ isPlaying: false });
        setActiveZoneId(null);
      }
    }
  }, [userLocation, zones, isTracking, activeZoneId, onStateChange, onResetPause]);

  return <div className="hidden" />;
};

export default AudioEngine;

