          <button onClick={onCancel} className="p-2 hover:bg-[#282828] rounded-full text-[#B3B3B3] transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] text-[#B3B3B3] font-black uppercase tracking-[0.2em]">{t.idLabel}</label>
            <div className="flex gap-2">
              <input 
                type="text" 
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder={t.idPlaceholder}
                className="flex-1 bg-[#282828] border-none rounded-lg p-4 text-white placeholder:text-[#535353] focus:ring-2 focus:ring-primary outline-none font-bold"
              />
              <button 
                onClick={handleGeminiSuggestion}
                disabled={isGenerating}
                className="bg-[#282828] p-4 rounded-lg text-primary hover:bg-[#3e3e3e] disabled:opacity-50 transition-all border border-white/5"
                title={t.suggestTip}
              >
                {isGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" fill="currentColor" />}
              </button>
            </div>
          </div>

          <div className="space-y-3">
            <label className="text-[10px] text-[#B3B3B3] font-black uppercase tracking-[0.2em] flex justify-between">
              <span>{t.rangeLabel}</span>
              <span className="text-primary">{radius}m</span>
            </label>
            <input 
              type="range" 
              min="10" 
              max="200" 
              step="10"
              value={radius} 
              onChange={(e) => setRadius(Number(e.target.value))}
              className="w-full h-1 bg-[#282828] rounded-lg appearance-none cursor-pointer accent-primary"
            />
          </div>

          <div className="bg-[#181818] p-6 rounded-2xl border border-white/5 space-y-4">
            <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-primary rounded-lg flex items-center justify-center">
                    <Music className="text-black w-5 h-5" />
                </div>
                <div>
                    <h4 className="text-sm font-black text-white uppercase tracking-tight">{t.audioTitle}</h4>
                    <p className="text-[10px] text-[#B3B3B3] font-bold">{t.audioDesc}</p>
                </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
                <div className="relative group">
                    <input 
                      type="file" 
                      accept="audio/*"
                      onChange={handleFileChange}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                    />
                    <div className="h-full flex flex-col items-center gap-2 p-4 bg-[#282828] rounded-2xl border border-transparent group-hover:border-primary transition-all text-center justify-center min-h-[100px]">
                      <Upload className="w-5 h-5 text-[#B3B3B3]" />
                      <div className="text-[10px] font-bold text-white line-clamp-2">
                        {musicFile ? musicFile.name : t.uploadAudio}
                      </div>
                    </div>
                </div>

                <div className="relative group">
                    <input 
                      type="file" 
                      accept="image/*"
                      onChange={handleCoverChange}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                    />
                    <div className="h-full flex flex-col items-center gap-2 p-4 bg-[#282828] rounded-2xl border border-transparent group-hover:border-primary transition-all text-center justify-center relative overflow-hidden min-h-[100px]">
                      {coverImage ? (
                        <img src={coverImage} className="absolute inset-0 w-full h-full object-cover opacity-40" alt="Cover preview" />
                      ) : (
