                            <span>{t.uploadCover}</span>
                            <span className="opacity-60 text-[8px]">{t.optional}</span>
                          </div>
                        )}
                      </div>
                    </div>
                </div>
            </div>
          </div>
        </div>

        <button 
          onClick={handleSave}
          disabled={!name || !musicFile}
          className="w-full bg-primary hover:brightness-110 text-black font-black py-4 rounded-full transition-all duration-200 disabled:opacity-30 disabled:grayscale active:scale-95 shadow-xl shadow-primary/20 uppercase tracking-widest text-sm"
        >
          {t.saveBtn}
        </button>
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #282828; border-radius: 10px; }
      `}</style>
    </div>
  );
};

