               <p className="text-xs text-[#B3B3B3] font-medium">
                  {zones.length} {translations.zones}
               </p>
               <div className="flex items-center gap-2">
                  {isTestMode ? (
                    <span className="text-[10px] font-bold text-black bg-primary px-2 py-0.5 rounded-full uppercase tracking-wider">{translations.test}</span>
