import React, { useEffect, useRef, useState } from 'react';
import { Zone, Coordinates, PlayerState } from '../types';
import { calculateDistance } from '../constants';

interface AudioEngineProps {
  userLocation: Coordinates | null;
  zones: Zone[];
  isTracking: boolean;
  onStateChange: (state: PlayerState) => void;
  isPaused: boolean;
  onResetPause: () => void;
  volume: number;
}

const AudioEngine: React.FC<AudioEngineProps> = ({ 
  userLocation, 
  zones, 
  isTracking, 
  onStateChange,
  isPaused,
  onResetPause,
  volume
}) => {
  const [activeZoneId, setActiveZoneId] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const currentMeta = useRef<{
    trackName?: string;
    zoneName?: string;
    coverUrl?: string;
  }>({});

  // Inicializar objeto de audio una sola vez
  useEffect(() => {
    const audio = new Audio();
    audio.volume = volume;
    audio.loop = true;
    audioRef.current = audio;

    return () => {
      audio.pause();
      audio.src = "";
    };
  }, []);

  // Manejar cambios de volumen global
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume;
    }
  }, [volume]);

  // Lógica Principal: Sincroniza el audio con la ubicación, la lista de zonas y el pausado manual
  useEffect(() => {
    if (!audioRef.current) return;

    // Si perdemos el tracking, pausamos por seguridad
    if (!isTracking || !userLocation) {
      if (activeZoneId) {
        audioRef.current.pause();
        onStateChange({ isPlaying: false, ...currentMeta.current });
      }
      return;
    }

    // 1. Buscamos si el usuario está en ALGUNA zona de la lista actual
    const currentZone = zones.find(zone => {
      const distance = calculateDistance(userLocation, zone.center);
      return distance <= zone.radius;
    });

    // 2. Comprobamos si la zona que estaba sonando ha sido eliminada
    const activeZoneStillExists = activeZoneId ? zones.some(z => z.id === activeZoneId) : false;

    // 3. Comportamiento basado en la zona y su existencia
    if (currentZone) {
      if (activeZoneId !== currentZone.id) {
        // ENTRANDO EN UNA NUEVA ZONA (O CAMBIO DE ZONA)
        console.log(`Entrando en zona: ${currentZone.name}`);

        // Al entrar en una zona nueva, siempre reseteamos el pause manual para que suene
        onResetPause();
        setActiveZoneId(currentZone.id);

        if (currentZone.music) {
          audioRef.current.src = currentZone.music.url;
          currentMeta.current = {
             trackName: currentZone.music.name,
             zoneName: currentZone.name,
             coverUrl: currentZone.music.coverUrl
          };
          audioRef.current.play().catch(e => console.log("Error al reproducir:", e));
          onStateChange({ isPlaying: true, ...currentMeta.current });
        }
      } else {
        // EL USUARIO SIGUE EN LA MISMA ZONA
        // Sincronizamos con el botón de pausa manual del reproductor
        if (isPaused) {
          if (!audioRef.current.paused) {
            audioRef.current.pause();
            onStateChange({ isPlaying: false, ...currentMeta.current });
          }
        } else {
          if (audioRef.current.paused && audioRef.current.src) {
            audioRef.current.play().catch(e => console.log("Error al reanudar:", e));
            onStateChange({ isPlaying: true, ...currentMeta.current });
          }
        }
      }
    } else {
      // EL USUARIO ESTÁ FUERA DE TODAS LAS ZONAS 
      // O LA ZONA ACTIVA FUE ELIMINADA (currentZone será undefined)
      if (activeZoneId !== null) {
        console.log("Saliendo de zona o zona eliminada -> Deteniendo música");
        audioRef.current.pause();
        audioRef.current.src = "";
        currentMeta.current = {};
        onStateChange({ isPlaying: false });
        setActiveZoneId(null);
      }
    }

    // Caso especial: Si el activeZoneId ya no existe en la lista de zones, forzamos parada
    if (activeZoneId && !activeZoneStillExists) {
        audioRef.current.pause();
        audioRef.current.src = "";
        currentMeta.current = {};
        onStateChange({ isPlaying: false });
        setActiveZoneId(null);
    }

  }, [userLocation, zones, isTracking, activeZoneId, isPaused, onStateChange, onResetPause]);

  return <div className="hidden" aria-hidden="true" />;
};

export default AudioEngine;

