                >
                  {settings.volume === 0 ? <VolumeX size={18} /> : settings.volume < 0.5 ? <Volume1 size={18} /> : <Volume2 size={18} />}
                </button>

                {showVolumeSlider && (
                  <div className="absolute bottom-full mb-4 left-1/2 -translate-x-1/2 bg-[#282828] p-4 rounded-2xl shadow-2xl border border-white/10 animate-in fade-in slide-in-from-bottom-2 duration-200">
                    <div className="h-32 w-8 flex flex-col items-center">
                       <input 
                        type="range"
                        min="0"
                        max="1"
                        step="0.01"
                        value={settings.volume}
                        onChange={(e) => onVolumeChange(parseFloat(e.target.value))}
                        className="w-24 -rotate-90 origin-center translate-y-8 h-2 bg-white/20 rounded-full appearance-none cursor-pointer accent-primary"
                      />
                    </div>
                  </div>
                )}
             </div>

             <button 
                onClick={onTogglePause}
                className="w-10 h-10 rounded-full flex items-center justify-center text-white transition-all hover:scale-110 active:scale-90 bg-primary/10 border border-primary/20"
             >
                 {isPaused ? <Play size={20} fill="currentColor" className="text-primary ml-1" /> : <Pause size={20} fill="currentColor" className="text-primary" />}
             </button>
        </div>
      </div>
    </div>
  );
};

