        setActiveZoneId(currentZone.id);

        if (currentZone.music) {
          audioRef.current.src = currentZone.music.url;
          currentMeta.current = {
             trackName: currentZone.music.name,
             zoneName: currentZone.name,
             coverUrl: currentZone.music.coverUrl
          };
          audioRef.current.play().catch(e => console.log("Auto-play blocked:", e));
          onStateChange({ isPlaying: true, ...currentMeta.current });
        }
      } else {
        // PERMANENCIA EN LA MISMA ZONA
        // Aquí gestionamos el Play/Pause manual del usuario
        if (isPaused) {
          if (!audioRef.current.paused) {
            audioRef.current.pause();
          }
          // Notificamos que NO está sonando pero MANTENEMOS la meta-data para que el player no desaparezca
          onStateChange({ isPlaying: false, ...currentMeta.current });
        } else {
          if (audioRef.current.paused && audioRef.current.src) {
            audioRef.current.play().catch(e => console.log("Resume failed:", e));
          }
          onStateChange({ isPlaying: true, ...currentMeta.current });
        }
      }
    } else {
      // SALIDA DE TODAS LAS ZONAS
      if (activeZoneId !== null) {
        console.log("Saliendo de zona -> Limpiando reproductor");
        audioRef.current.pause();
        audioRef.current.src = "";
        currentMeta.current = {};
        onStateChange({ isPlaying: false });
        setActiveZoneId(null);
      }
    }

    // CASO ESPECIAL: Borrado de la zona activa mientras estás dentro
    if (activeZoneId && !activeZoneStillExists) {
        audioRef.current.pause();
        audioRef.current.src = "";
        currentMeta.current = {};
        onStateChange({ isPlaying: false });
        setActiveZoneId(null);
    }

  }, [userLocation, zones, isTracking, activeZoneId, isPaused, onStateChange, onResetPause]);

  return <div className="hidden" aria-hidden="true" />;
};

export default AudioEngine;

