import React, { useEffect, useRef, useState } from 'react';
import { Zone, Coordinates, PlayerState } from '../types';
import { calculateDistance } from '../constants';

interface AudioEngineProps {
  userLocation: Coordinates | null;
  zones: Zone[];
  isTracking: boolean;
  onStateChange: (state: PlayerState) => void;
  isPaused: boolean;
  onResetPause: () => void;
  volume: number;
}

const AudioEngine: React.FC<AudioEngineProps> = ({ 
  userLocation, 
  zones, 
  isTracking, 
  onStateChange,
  isPaused,
  onResetPause,
  volume
}) => {
  const [activeZoneId, setActiveZoneId] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const currentMeta = useRef<{
    trackName?: string;
    zoneName?: string;
    coverUrl?: string;
  }>({});

  // Inicialización única
  useEffect(() => {
    const audio = new Audio();
    audio.volume = volume;
    audio.loop = true;
    audioRef.current = audio;

    return () => {
      audio.pause();
      audio.src = "";
    };
  }, []);

  // Sincronización de volumen constante (no se ve afectado por la pausa)
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume;
    }
  }, [volume]);

  useEffect(() => {
    if (!audioRef.current) return;

    if (!isTracking || !userLocation) {
      if (activeZoneId && !audioRef.current.paused) {
        audioRef.current.pause();
        onStateChange({ isPlaying: false, ...currentMeta.current });
      }
      return;
    }

    const currentZone = zones.find(zone => {
      const distance = calculateDistance(userLocation, zone.center);
      return distance <= zone.radius;
    });

    const activeZoneStillExists = activeZoneId ? zones.some(z => z.id === activeZoneId) : false;

    if (currentZone) {
      if (activeZoneId !== currentZone.id) {
        // Nueva zona detectada
        onResetPause();
        setActiveZoneId(currentZone.id);

        if (currentZone.music) {
          audioRef.current.src = currentZone.music.url;
          currentMeta.current = {
             trackName: currentZone.music.name,
             zoneName: currentZone.name,
             coverUrl: currentZone.music.coverUrl
          };
          audioRef.current.play().catch(e => console.warn("Reproducción bloqueada por el navegador", e));
          onStateChange({ isPlaying: true, ...currentMeta.current });
        }
      } else {
        // El usuario permanece en la zona: Gestionamos el botón de pausa manual
        if (isPaused) {
          if (!audioRef.current.paused) {
            audioRef.current.pause(); // Pausa real del audio
          }
          onStateChange({ isPlaying: false, ...currentMeta.current });
        } else {
          if (audioRef.current.paused && audioRef.current.src) {
            audioRef.current.play().catch(e => console.warn("Error al reanudar", e));
          }
          onStateChange({ isPlaying: true, ...currentMeta.current });
        }
      }
    } else {
      // Fuera de zonas
      if (activeZoneId !== null) {
        audioRef.current.pause();
        audioRef.current.src = "";
        currentMeta.current = {};
        onStateChange({ isPlaying: false });
        setActiveZoneId(null);
      }
    }

    if (activeZoneId && !activeZoneStillExists) {
        audioRef.current.pause();
        audioRef.current.src = "";
        currentMeta.current = {};
        onStateChange({ isPlaying: false });
        setActiveZoneId(null);
    }

  }, [userLocation, zones, isTracking, activeZoneId, isPaused, onStateChange, onResetPause]);

  return <div className="hidden" aria-hidden="true" />;
};

export default AudioEngine;

