              <div className="w-full space-y-2">
                <label className="text-[10px] font-black uppercase text-[#B3B3B3] ml-2">{t.userNameLabel}</label>
                <input type="text" value={settings.userName} onChange={(e) => onUpdate({ ...settings, userName: e.target.value })} className="w-full bg-[#282828] border-none rounded-2xl p-4 text-white focus:ring-2 focus:ring-primary outline-none font-bold" placeholder={t.userNamePlaceholder} />
              </div>
              <p className="text-xs text-[#B3B3B3] text-center px-6">{t.profileInfo}</p>
            </div>
          )}

          {activeTab === 'volume' && (
            <div className="space-y-8 py-4">
               <div className="bg-[#282828] p-8 rounded-[40px] flex flex-col items-center gap-6 border border-white/5 relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-full h-1 bg-primary/20"><div className="h-full bg-primary" style={{ width: `${settings.volume * 100}%` }} /></div>
                  <div className="w-24 h-24 rounded-full bg-primary/10 flex items-center justify-center text-primary border-2 border-primary/20">{settings.volume === 0 ? <VolumeX size={48} /> : settings.volume < 0.5 ? <Volume1 size={48} /> : <Volume2 size={48} />}</div>
                  <div className="w-full space-y-4">
                    <div className="flex justify-between items-center px-2"><span className="text-[10px] font-black text-[#B3B3B3] uppercase tracking-widest">{t.volumeLabel}</span><span className="text-xl font-black text-primary">{Math.round(settings.volume * 100)}%</span></div>
                    <input type="range" min="0" max="1" step="0.01" value={settings.volume} onChange={(e) => onUpdate({ ...settings, volume: parseFloat(e.target.value) })} className="w-full h-4 bg-white/5 rounded-full appearance-none cursor-pointer accent-primary" />
                  </div>
               </div>
               <div className="flex gap-4">
                  <button onClick={() => onUpdate({ ...settings, volume: 0 })} className="flex-1 py-4 bg-[#282828] text-[#B3B3B3] rounded-2xl font-black text-xs uppercase">{t.mute}</button>
                  <button onClick={() => onUpdate({ ...settings, volume: 1 })} className="flex-1 py-4 bg-[#282828] text-primary rounded-2xl font-black text-xs uppercase">MAX</button>
               </div>
            </div>
          )}
        </div>

        <div className="p-6 bg-[#181818] border-t border-white/5">
           <button onClick={activeTab === 'root' ? onClose : () => setActiveTab('root')} className="w-full py-4 bg-primary text-black font-black rounded-full uppercase tracking-widest text-xs shadow-lg active:scale-95 transition-all">
             {activeTab === 'root' ? t.close : t.back}
           </button>
        </div>
      </div>
    </div>
  );
};

export default SettingsModal;

